```class Solution {
public:
    int addMinimum(string word) {
        int res = 0, cnt = 0;
        for (char c : word) {
            cnt = (cnt * 3 + (c - 'a' + 1)) % 3;
            res += (cnt == 0) ? 0 : 3 - cnt;
        }
        return res;
    }
};
